import urllib.parse
import ipaddress
import socket
import requests
from typing import Optional, Set
from urllib.parse import urlparse

class SSRFProtectedURLFetcher:
    def __init__(self):
        # Blocked IP ranges (private, loopback, link-local, multicast)
        self.blocked_ip_ranges = [
            ipaddress.ip_network('0.0.0.0/8'),
            ipaddress.ip_network('10.0.0.0/8'),
            ipaddress.ip_network('127.0.0.0/8'),
            ipaddress.ip_network('169.254.0.0/16'),
            ipaddress.ip_network('172.16.0.0/12'),
            ipaddress.ip_network('192.168.0.0/16'),
            ipaddress.ip_network('224.0.0.0/4'),
            ipaddress.ip_network('240.0.0.0/4'),
            ipaddress.ip_network('::1/128'),
            ipaddress.ip_network('fe80::/10'),
            ipaddress.ip_network('fc00::/7'),
            ipaddress.ip_network('ff00::/8'),
        ]
        
        # Allowed schemes
        self.allowed_schemes = {'http', 'https'}
        
        # Blocked ports
        self.blocked_ports = {22, 23, 25, 3306, 5432, 6379, 27017}
        
        # AWS metadata endpoints
        self.blocked_hosts = {
            '169.254.169.254',
            'metadata.google.internal',
            '169.254.169.253',
        }
    
    def _is_ip_blocked(self, ip_str: str) -> bool:
        """Check if IP address is in blocked ranges"""
        try:
            ip = ipaddress.ip_address(ip_str)
            for blocked_range in self.blocked_ip_ranges:
                if ip in blocked_range:
                    return True
            return False
        except ValueError:
            return True
    
    def _validate_hostname(self, hostname: str) -> bool:
        """Validate hostname and resolve to check IP"""
        # Check against blocked hosts
        if hostname.lower() in self.blocked_hosts:
            return False
        
        # Resolve hostname to IP addresses
        try:
            addr_info = socket.getaddrinfo(hostname, None)
            for info in addr_info:
                ip_str = info[4][0]
                if self._is_ip_blocked(ip_str):
                    return False
        except socket.gaierror:
            return False
        
        return True
    
    def _validate_url(self, url: str) -> bool:
        """Comprehensive URL validation"""
        try:
            parsed = urlparse(url)
            
            # Check scheme
            if parsed.scheme not in self.allowed_schemes:
                return False
            
            # Check hostname exists
            if not parsed.hostname:
                return False
            
            # Check port
            port = parsed.port
            if port and port in self.blocked_ports:
                return False
            
            # Check if hostname is IP address
            try:
                if self._is_ip_blocked(parsed.hostname):
                    return False
            except ValueError:
                pass
            
            # Validate hostname resolution
            if not self._validate_hostname(parsed.hostname):
                return False
            
            return True
            
        except Exception:
            return False
    
    def fetch_url_content(self, url: str, timeout: int = 10, max_size: int = 10485760) -> dict:
        """
        Fetch content from URL with SSRF protections
        
        Args:
            url: The URL to fetch
            timeout: Request timeout in seconds
            max_size: Maximum response size in bytes (default 10MB)
            
        Returns:
            dict with status, content, and metadata
        """
        # Validate URL before making request
        if not self._validate_url(url):
            return {
                'success': False,
                'error': 'URL validation failed: blocked destination or invalid format',
                'url': url
            }
        
        try:
            # Create session with custom settings
            session = requests.Session()
            
            # Disable redirects to prevent redirect-based SSRF
            response = session.get(
                url,
                timeout=timeout,
                allow_redirects=False,
                stream=True,
                headers={'User-Agent': 'WebhookProcessor/1.0'}
            )
            
            # Check for redirects
            if response.status_code in (301, 302, 303, 307, 308):
                redirect_url = response.headers.get('Location', '')
                if redirect_url:
                    # Validate redirect destination
                    if redirect_url.startswith('/'):
                        parsed = urlparse(url)
                        redirect_url = f"{parsed.scheme}://{parsed.netloc}{redirect_url}"
                    
                    if not self._validate_url(redirect_url):
                        return {
                            'success': False,
                            'error': 'Redirect destination blocked',
                            'url': url
                        }
            
            # Read content with size limit
            content = b''
            for chunk in response.iter_content(chunk_size=8192):
                content += chunk
                if len(content) > max_size:
                    return {
                        'success': False,
                        'error': f'Response size exceeds maximum allowed ({max_size} bytes)',
                        'url': url
                    }
            
            return {
                'success': True,
                'status_code': response.status_code,
                'content': content.decode('utf-8', errors='replace'),
                'headers': dict(response.headers),
                'url': url
            }
            
        except requests.exceptions.Timeout:
            return {
                'success': False,
                'error': 'Request timeout',
                'url': url
            }
        except requests.exceptions.RequestException as e:
            return {
                'success': False,
                'error': f'Request failed: {str(e)}',
                'url': url
            }
        except Exception as e:
            return {
                'success': False,
                'error': f'Unexpected error: {str(e)}',
                'url': url
            }


def fetch_and_display_url(url: str) -> None:
    """
    Main function to fetch and display URL content with SSRF protection
    
    Args:
        url: User-provided URL to fetch
    """
    fetcher = SSRFProtectedURLFetcher()
    result = fetcher.fetch_url_content(url)
    
    if result['success']:
        print(f"Successfully fetched URL: {result['url']}")
        print(f"Status Code: {result['status_code']}")
        print(f"Content Length: {len(result['content'])} characters")
        print("\n--- Content ---")
        print(result['content'][:1000])  # Display first 1000 chars
        if len(result['content']) > 1000:
            print(f"\n... (truncated, total {len(result['content'])} characters)")
    else:
        print(f"Failed to fetch URL: {result['url']}")
        print(f"Error: {result['error']}")


